#include <stdio.h>
#include <stdlib.h>

int find_lru(int time[], int frames) {
    int minimum = time[0], lru_index = 0;
    for (int i = 1; i < frames; i++) {
        if (time[i] < minimum) {
            minimum = time[i];
            lru_index = i;
        }
    }
    return lru_index;
}

int lru_page_replacement(int pages[], int n, int frames) {
    int frame[frames], time[frames];
    int page_faults = 0, counter = 0;

    for (int i = 0; i < frames; i++) {
        frame[i] = -1;  // Initialize frames as empty
        time[i] = 0;
    }

    for (int i = 0; i < n; i++) {
        int page = pages[i], found = 0;

        // Check if page already in frame
        for (int j = 0; j < frames; j++) {
            if (frame[j] == page) {
                found = 1;
                time[j] = ++counter;
                break;
            }
        }

        // Page fault - replace LRU page
        if (!found) {
            page_faults++;
            int lru_index = find_lru(time, frames);
            frame[lru_index] = page;
            time[lru_index] = ++counter;
        }
    }
    return page_faults;
}

int main() {
    int pages[] = {7, 0, 1, 2, 0, 3, 0, 4, 2, 3};
    int n = sizeof(pages) / sizeof(pages[0]);
    int frames = 3;
    printf("LRU Page Faults: %d\n", lru_page_replacement(pages, n, frames));
    return 0;
}

def optimal_page_replacement(pages, frames):
    page_faults = 0
    memory = []  # frames in memory

    for i, page in enumerate(pages):
        if page not in memory:
            page_faults += 1
            if len(memory) < frames:
                memory.append(page)
            else:
                # Find page that won't be used for longest time
                farthest_use = -1
                victim_page = None
                for frame_page in memory:
                    try:
                        next_use = pages[i+1:].index(frame_page)
                    except ValueError:
                        next_use = float('inf')  # Never used again

                    if next_use > farthest_use:
                        farthest_use = next_use
                        victim_page = frame_page

                memory.remove(victim_page)
                memory.append(page)
        print(f"Page {page}: Frames {memory}")

    return page_faults

