public class FirstFitAllocation {
    static class Block {
        int size;
        boolean allocated;

        Block(int size) {
            this.size = size;
            this.allocated = false;
        }
    }

    static class Process {
        int size;
        int blockIndex;

        Process(int size) {
            this.size = size;
            this.blockIndex = -1;
        }
    }

    public static void allocateFirstFit(Block[] memory, Process[] processes) {
        for (Process p : processes) {
            for (int i = 0; i < memory.length; i++) {
                if (!memory[i].allocated && memory[i].size >= p.size) {
                    p.blockIndex = i;
                    memory[i].allocated = true;
                    System.out.println("Process size " + p.size + 
                        " allocated to block " + i);
                    break;
                }
            }
            if (p.blockIndex == -1) {
                System.out.println("Process size " + p.size + 
                    " could not be allocated");
            }
        }
    }

    public static void main(String[] args) {
        Block[] memory = {new Block(100), new Block(200), 
                         new Block(50), new Block(150)};
        Process[] processes = {new Process(30), new Process(100),
                              new Process(80), new Process(60)};

        allocateFirstFit(memory, processes);
    }
}
